  (154, 'Superfondo Renta Fija Latam', 3, 49, 96, 'Renta Fija', 'Latinoamerica', 'Largo Plazo', NULL, 2, '2016-06-21', 1, '198', 'Fondo de renta fija de largo plazo con posición en deuda latinoamericana soberana y corporativa, nominada en dólares. Horizonte de Inversión: 24 meses', 5),
  (797, 'Superfondo Renta Global', 3, 49, 96, 'Renta Fija', 'Global', 'Mediano Plazo', NULL, 180, '2018-02-06', 1, '1004', NULL, 5),
