  (51, 'Superfondo Renta Variable', 2, 49, 96, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '1995-05-16', 1, '138', 'Intenta maximizar el retorno de las inversiones a través de la selección de activos Argentinos que mejor reflejen las expectativas económicas, teniendo como benchmark el MAR (Merval Argentina)', 2),
  (1342, 'Superfondo Sustentable ASG', 10, 49, 96, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2022-08-16', 1, '1314', 'Inversiones en activos sustentanbles ASG', 2),
  (226, 'Supergestion', 5, 49, 96, 'Renta Mixta', 'Global', 'Largo Plazo', NULL, 1, '1998-02-13', 1, '252', 'Fondo mixto compuesto mayormente por renta fija argentina y renta variable local, latinoamericana, europea y estadounidense.', 2),
  (541, 'Supergestion Balanceado', 5, 49, 96, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2012-10-30', 1, '660', NULL, 2),
  (406, 'Supergestion Mix VI', 3, 49, 96, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2006-08-28', 1, '524', 'El objetivo de este Fondo es obtener un rendimiento cercano a la tasa encuesta BCRA (BADLAR) posicionándose en instrumentos de renta fija local tanto públicos como de empresas privadas y en colocaciones a tasa en el sistema financiero argentino respetando los siguientes límites: - Máxima posición a devengamiento: 20% - Máxima posición en Obligaciones Negociables: 30% - y Títulos Públicos: 100% El fondo está orientado a clientes con perfil de riesgo conservador que quieran invertir en deuda en pesos de corto plazo a través de obligaciones negociables, plazo fijos y títulos públicos, con una duration inferior a 180 días.', 1),
  (1782, 'Tandem Balanceado I', 5, 3163, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2026-01-05', 1, '1827', 'Sin datos', 1),
  (1783, 'Tandem Balanceado II', 5, 3163, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2026-01-05', 1, '1830', 'Sin datos', 1),
  (1795, 'Tandem Crecimiento I', 5, 3163, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2026-02-01', 1, '1850', 'Sin datos', 1),
  (1511, 'Tandem Dólares Retorno Total', 7, 3163, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 2, '2024-06-03', 1, '1489', 'Obtener la apreciación de valor del patrimonio del Fondo. A tal fin, el Fondo invertirá en valores negociables, instrumentos financieros y otros activos financieros de renta fija o variable, de carácter público o privado, nacionales o extranjeros.', 2),
  (1796, 'Tandem Global', 5, 3163, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 2, '2026-02-01', 1, '1851', 'Sin datos', 1),
  (1850, 'Tandem Global II', 5, 3163, 65, 'Renta Mixta', 'Argentina', 'Corto Plazo', NULL, 180, '2026-04-23', 1, '1916', 'Inversiones de instrumentos de Renta Fija y Variable', 1),
  (1510, 'Tandem Pesos Ahorro Plus', 3, 3163, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2024-06-03', 1, '1488', 'Obtener una apreciación de su valor patrimonial, a través de la inversión en activos y la administración de una cartera diversificada de inversiones en instrumentos financieros y valores negociables, principalmente  de renta fija.', 1),
  (1784, 'Tandem Renta Pesos', 4, 3163, 115, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2026-01-05', 1, '1828', 'Sin datos', 0),
  (1823, 'Tango Money Market Dinámico', 4, 3405, 65, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2026-03-10', 1, '1867', 'Preservar el valor del patrimonio del FCI y obtener ingresos corrrientes y ganancias de capital por la compra y venta de activos autorizados. Al menos un 75% del patrimonio neto del FCI deben ser activos de renta fija argentina en pesos, y de una duracion igual o menor a 1 año-', 0),
  (1320, 'Terrazas Del Volcan Inmobiliario FCIC', 9, 2545, 65, 'Cerrado', 'Argentina', 'Largo Plazo', NULL, 1, '2022-06-13', 1, '1280', 'El fondo tiene como objetivo especial la inversión en activos específicos.', 0),
  (52, 'Toronto Trust', 3, 27, 398, 'Renta Fija', 'Global', 'Flexible', NULL, 1, '2017-09-06', 1, '62', 'El objetivo del fondo consiste en la apreciación de capital, con una exposición al riesgo moderada. El fondo invierte, a la fecha, principalmente en activos locales de renta fija de mediano plazo, denominados en pesos y dólares.', 1),
  (577, 'Toronto Trust Abierto Pymes', 6, 27, 398, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2013-12-23', 1, '720', 'El objetivo del fondo consiste en la apreciación de capital a través de la inversión en instrumentos de pequeñas y medianas empresas, con una exposición al riesgo moderada. El fondo invierte, a la fecha, principalmente en activos pyme de renta fija de corto, mediano plazo y largo plazo, denominados en pesos y dólares.', 1),
  (560, 'Toronto Trust Ahorro', 4, 27, 398, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2013-06-26', 1, '707', 'El fondo tiene como objetivo brindar rendimiento a la liquidez, priorizando la preservación de capital. A tal fin, invierte principalmente en una cartera diversificada de plazos fijos y cuentas a la vista en entidades financieras.', 0),
  (1815, 'Toronto Trust Ahorro Dólar', 5, 27, 398, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 2, '2026-02-27', 1, '1462', 'apreciación del patrimonio del FONDO mediante ingresos corrientes y ganancias de capital por la compra y venta de ACTIVOS AUTORIZADOS.', 1),
  (1310, 'Toronto Trust Argentina 2021', 5, 27, 398, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2022-02-24', 1, '913', 'Apreciación del patrimonio del FONDO mediante ingresos corrientes y ganancias de capital por la compra y venta de ACTIVOS AUTORIZADOS', 1),
  (1416, 'Toronto Trust Balanceado', 5, 27, 398, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2023-06-21', 1, '1389', 'Apreciación del patrimonio del fondo mediante ingresos corrientes y ganancias de capital por la compra y venta de activos autorizados.', 1),
  (775, 'Toronto Trust Crecimiento', 3, 27, 398, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 2, '2017-10-17', 1, '966', 'El objetivo del fondo consiste en la preservación de capital en dólares, a través de la inversión en activos denominados en dólares de corto/mediano plazo. El fondo permite administrar activos en dólares ofreciendo un rendimiento competitivo vis-a-vis otras alternativas de inversión en dólares de similares características.', 1),
  (1394, 'Toronto Trust Gestión', 5, 27, 398, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2023-03-13', 1, '1326', 'Apreciación del patrimonio del FONDO mediante ingresos corrientes y ganancias de capital por la compra y venta de Activos Autorizados.', 0),
  (578, 'Toronto Trust Global Capital', 3, 27, 398, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2013-12-23', 1, '721', NULL, 1),
  (1539, 'Toronto Trust Infraestructura', 5, 27, 398, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2024-08-01', 1, '1484', 'Apreciación del patrimonio del fondo mediante ingresos corrientes y ganancias de capital por la compra y venta de activos autorizados.', 1),
  (733, 'Toronto Trust Liquidez Dólar', 3, 27, 398, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 2, '2017-03-21', 1, '898', NULL, 2),
  (1567, 'Toronto Trust Money Market Dólar', 4, 27, 398, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 2, '2024-09-26', 1, '1578', 'Preservar el capital y, en ese marco, intentar obtener una apreciación de su valor patrimonial, mediante ingresos corrientes y ganancias de capital por la compra y venta de activos autorizados.', 0),
  (561, 'Toronto Trust Multimercado', 2, 27, 398, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-06', 1, '699', 'El fondo tiene como objetivo la apreciación del patrimonio a mediano / largo plazo. A la fecha invierte principalmente en acciones argentinas.', 1),
  (1482, 'Toronto Trust Renta Dólar', 5, 27, 398, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 2, '2024-03-12', 1, '1463', 'Apreciación del patrimonio del fondo mediante ingresos corrientes y ganancias de capital por la compra y venta de activos autorizados.', 1),
  (562, 'Toronto Trust Renta Fija', 3, 27, 398, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2013-06-26', 1, '700', 'El fondo tiene como objetivo obtener una renta cercana a la tasa de interés para plazos fijos mayoristas a 30 días, con un bajo nivel de volatilidad. A tal fin, invierte en instrumentos de renta fija de corto plazo, incluyendo fideicomisos financieros, obligaciones negociables, títulos públicos, letras provinciales y letras y notas del BCRA, entre otros.', 1),
  (563, 'Toronto Trust Renta Fija Plus', 3, 27, 398, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-06', 1, '701', 'El objetivo del fondo consiste en preservar el capital en un horizonte de mediano plazo, generando rendimiento a través de ingresos corrientes y ganancias de capital, invirtiendo principalmente en activos de renta fija de emisores argentinos, denominados en dólares.', 1),
  (776, 'Toronto Trust Retorno Total', 3, 27, 398, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-22', 1, '965', NULL, 1),
